window.ITEMS_UNIT4=[{"problem_id":"unit04-0001","original_source":"cpm-5-26","source_lesson":"Lesson 5.1.2","category":"Unit 4: Function Families and Transformations","section":"1","unit_section_title":"Unit 4, Section 1: Association and Lines of Best Fit","source_type":"Review/Preview","audit_status":"authoritative","notes":"Describes association in a scatterplot.","question_html":"<section class=\"problem\" id=\"5-26\"><h2>5-26</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 2, Section 5: Linear Modeling with Data</div><div class=\"audit\">Audit note: Describes association in a scatterplot.</div>\n<div class=\"contentContainerReference-body\"><div class=\"row\"><div class=\"col-sm-6\"><p class=\"\" style=\"\">The graph at right compares the age and the number of pets for a certain population.<br/><br/>Describe the association for this population. </p><p class=\"\" style=\"\"></p></div><div class=\"col-sm-6 col-align-top\" style=\"text-align:center;\"><p class=\"\" style=\"\"></p></div></div></div><img alt=\"Scatterplot comparing age and number of pets\" class=\"figure-img\" src=\"assets/5-26.png\"/>\n</section>"},{"problem_id":"unit04-0002","original_source":"cpm-5-27","source_lesson":"Lesson 5.1.2","category":"Unit 4: Function Families and Transformations","section":"1","unit_section_title":"Unit 4, Section 1: Association and Lines of Best Fit","source_type":"Review/Preview","audit_status":"authoritative","notes":"Uses a scatterplot, line of best fit, and contextual prediction.","question_html":"<section class=\"problem\" id=\"5-27\"><h2>5-27</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 2, Section 5: Linear Modeling with Data</div><div class=\"audit\">Audit note: Uses a scatterplot to find a line of best fit and make a contextual prediction.</div>\n<div class=\"contentContainerReference-body\"><div class=\"row\"><div class=\"col-xl-8\"><p class=\"\" style=\"\">At an aunt\u2019s wedding, Nicolas collected data about an ice sculpture that was about to completely melt. A graph of his data is shown at right. </p><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\" style=\"\">Calculate the equation of a line of best fit.</p></li><li><p class=\"\" style=\"\">Based on your equation, how tall was the ice sculpture one hour before Nicolas started measuring?</p></li></ol></div><div class=\"col-xl-4 col-align-top\" style=\"text-align:center;\"><p class=\"\" style=\"\"></p></div></div></div><img alt=\"Scatterplot of ice sculpture height over time\" class=\"figure-img\" src=\"assets/5-27.png\"/><div class=\"workspace workspace-lg\"></div>\n</section>"},{"problem_id":"unit04-0003","original_source":"cpm-5-88","source_lesson":"Lesson 5.3.1","category":"Unit 4: Function Families and Transformations","section":"1","unit_section_title":"Unit 4, Section 1: Association and Lines of Best Fit","source_type":"Review/Preview","audit_status":"authoritative","notes":"Interprets association in a scatterplot comparing gas mileage and vehicle weight.","question_html":"<section class=\"problem\" id=\"5-88\">\n<h2>5-88</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 2, Section 5: Linear Modeling with Data</div>\n<div class=\"audit\">Audit note: Interprets association in a scatterplot comparing gas mileage and vehicle weight.</div>\n<div><div class=\"row\"><div class=\"col-xl-8\"><p>The graph at right compares the gas mileage to the weight of numerous vehicles. </p><p>Describe the association between these two quantities.</p></div><div class=\"col-xl-4 col-align-top\"><p><img alt=\"Scatterplot comparing vehicle weight and gas mileage\" class=\"figure-img\" src=\"assets/5-88.png\"/></p></div></div></div>\n</section>"},{"problem_id":"unit04-0004","original_source":"cpm-5-110","source_lesson":"Lesson 5.3.2","category":"Unit 4: Function Families and Transformations","section":"1","unit_section_title":"Unit 4, Section 1: Association and Lines of Best Fit","source_type":"Review/Preview","audit_status":"authoritative","notes":"Writes and uses a line of best fit from a scatterplot.","question_html":"<section class=\"problem\" id=\"5-110\">\n<h2>5-110</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 2, Section 5: Linear Modeling with Data</div>\n<div class=\"audit\">Audit note: Writes and uses a line of best fit from a scatterplot.</div>\n<div><div class=\"row\"><div class=\"col-xl-8\"><p>The graph at right shows a comparison of the length of several gold chain necklaces (including the clasp) to the total mass. </p><ol class=\"lower-alpha\" type=\"a\"><li><p>Write an equation for the line of best fit.</p></li><li><p>Based on your equation, what would you expect to be the mass of a $26$ inch chain?</p></li></ol></div><div class=\"col-xl-4 col-align-top\"><p><img alt=\"Scatterplot of necklace length and mass\" class=\"figure-img\" src=\"assets/5-110.png\"/></p></div></div></div>\n</section>"},{"problem_id":"unit04-0005","original_source":"cpm-1-47","source_lesson":"1.2.2","category":"Unit 4: Function Families and Transformations","section":"2","unit_section_title":"Unit 4, Section 2: Translations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Analyzes a translated absolute-value graph using graph-investigation questions.","question_html":"<section class=\"problem\" id=\"1-47\"><h2>1-47</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 1, Section 3: Parent Functions</div><div class=\"audit\">Audit note: Uses graph investigation questions to analyze an absolute-value graph.</div>\n<p>Use your list of graph investigation questions from your Learning Log to answer questions about the graph shown below. <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/irhqvweqe5\" rel=\"noopener\" target=\"_blank\">1-47 HW eTool</a></p>\n<img alt=\"Absolute value graph for y equals absolute value of x plus 2 minus 1.\" class=\"figure figure-lg figure-no-border figure-img wide-figure\" src=\"assets/1-47.png\"/>\n</section>","resources":[{"label":"1-47 HW eTool","href":"https://www.desmos.com/calculator/irhqvweqe5"}]},{"problem_id":"unit04-0006","original_source":"cpm-1-59","source_lesson":"1.2.3","category":"Unit 4: Function Families and Transformations","section":"2","unit_section_title":"Unit 4, Section 2: Translations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Graphs and describes a translated cube-root function.","question_html":"<section class=\"problem\" id=\"1-59\"><h2>1-59</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 1, Section 3: Parent Functions</div><div class=\"audit\">Audit note: Graphs and describes a translated cube-root function.</div>\n<p>Graph and fully describe the function $y=\\sqrt[3]{x}-2$.</p>\n</section>"},{"problem_id":"unit04-0007","original_source":"cpm-6-58","source_lesson":"6.2.1","category":"Unit 4: Function Families and Transformations","section":"2","unit_section_title":"Unit 4, Section 2: Translations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Translated quadratic graph; horizontal/vertical shift is the primary focus.","question_html":"<section class=\"problem\" id=\"6-58\">\n<h2>6-58</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 5: Polynomial Structure &amp; Quadratic Graphs</div>\n<div class=\"audit\">Audit note: Graphs and describes a translated quadratic function.</div>\n<div><p>Graph <em>$y = \\left(x - 2\\right)^{2} - 1$</em>. Completely describe the graph. \u00a0\u00a0</p></div>\n</section>"},{"problem_id":"unit04-0008","original_source":"cpm-7-64","source_lesson":"7.1.5","category":"Unit 4: Function Families and Transformations","section":"2","unit_section_title":"Unit 4, Section 2: Translations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Compares translated quadratic graphs to the parent quadratic.","question_html":"<section class=\"problem\" id=\"7-64\">\n<h2>7-64</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 2: Translations</div>\n<div class=\"audit\">Audit note: Compares translated quadratic graphs to the parent quadratic function.</div>\n<div><p>Graph <em>$y=x^2+3$</em> and <em>$y=(x+3)^2$</em>. What are the similarities and differences between the graphs? How do these graphs compare to the graph of <em>$y=x^2$</em>?  <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/magqicv2uh\" rel=\"noopener\" target=\"_blank\">7-64 HW eTool</a></p></div>\n</section>","resources":[{"label":"7-64 HW eTool","href":"https://www.desmos.com/calculator/magqicv2uh"}]},{"problem_id":"unit04-0009","original_source":"cpm-11-1","source_lesson":"11.1.1","category":"Unit 4: Function Families and Transformations","section":"2","unit_section_title":"Unit 4, Section 2: Translations","source_type":"Lesson","audit_status":"authoritative","notes":"Investigates f(x)+k on linear and quadratic functions; vertical shifts/translation effects dominate.","question_html":"<section class=\"problem\" id=\"11-1\">\n<h2>11-1</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 1, Section 2: Inputs and Outputs</div>\n<div class=\"audit\">Audit note: Investigates vertical transformations f(x)+k for linear and quadratic functions and connects changes in graph to equation.</div>\n<p><strong>FUNCTIONS OF AMERICA.</strong> Your customers at Functions of America want unique lines and curves, not the same ones used by everybody else. However, they cannot afford custom-made functions. Instead you suggest that they order small modifications to in-stock functions. Perhaps your customers would be happy adding or subtracting a little bit to $f(x)=2x+4$ or $f(x)=3x^2-4$.</p>\n<ol class=\"lower-alpha\" type=\"a\"><li>Consider the transformation $f(x)+k$, where $k$ is any real number. What is the impact of this transformation on the original line, $f(x)=2x+4$? Investigate the impact on both the graph of the line and the algebraic equation of the line.</li><li>What is the impact of the transformation $f(x)+k$ on a parabola like $f(x)=3x^2-4$? Again, investigate the impact on both the graph of the parabola and its algebraic equation.</li></ol>\n</section>"},{"problem_id":"unit04-0010","original_source":"cpm-11-35","source_lesson":"11.2.1","category":"Unit 4: Function Families and Transformations","section":"2","unit_section_title":"Unit 4, Section 2: Function Families and Transformations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Investigates a square-root function, including domain, range, and graph features.","question_html":"<section class=\"problem\" id=\"11-35\">\n<h2>11-35</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 2: Function Families and Transformations</div>\n<div class=\"audit\">Audit note: Fully investigates a square-root function, including transformation features such as domain, range, intercepts, and graph behavior.</div>\n<p>Fully investigate the function $g(x)=\\sqrt{x-3}+1$. <a class=\"resource\" href=\"https://www.desmos.com/calculator/nxspcg4efp\" rel=\"noopener\" target=\"_blank\">11-35 HW eTool</a></p>\n</section>","resources":[{"label":"11-35 HW eTool","href":"https://www.desmos.com/calculator/nxspcg4efp"}]},{"problem_id":"unit04-0011","original_source":"cpm-11-77","source_lesson":"11.3.1","category":"Unit 4: Function Families and Transformations","section":"2","unit_section_title":"Unit 4, Section 2: Function Families and Transformations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Graphs a transformed square-root function and determines domain/range.","question_html":"<section class=\"problem\" id=\"11-77\">\n<h2>11-77</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 2: Function Families and Transformations</div>\n<div class=\"audit\">Audit note: Graphs a transformed square-root function and identifies its domain and range using inequalities.</div>\n<p>Graph the function $h(x)=-\\sqrt{3-x}$. Use inequalities to describe its domain and range. <a class=\"resource\" href=\"https://www.desmos.com/calculator/gioucwtgrv\" rel=\"noopener\" target=\"_blank\">11-77 HW eTool</a></p></section>","resources":[{"label":"11-77 HW eTool","href":"https://www.desmos.com/calculator/gioucwtgrv"}]},{"problem_id":"unit04-0012","original_source":"cpm-11-84","source_lesson":"11.3.1","category":"Unit 4: Function Families and Transformations","section":"2","unit_section_title":"Unit 4, Section 2: Function Families and Transformations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Graphs an absolute-value transformation and identifies special points.","question_html":"<section class=\"problem\" id=\"11-84\">\n<h2>11-84</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 2: Function Families and Transformations</div>\n<div class=\"audit\">Audit note: Graphs an absolute-value function transformation and identifies special points.</div>\n<p>Graph the function $f(x)=|x-3|-1$ and label all of its special points. <a class=\"resource\" href=\"https://www.desmos.com/calculator/dccrfjkmsc\" rel=\"noopener\" target=\"_blank\">11-84 HW eTool</a></p></section>","resources":[{"label":"11-84 HW eTool","href":"https://www.desmos.com/calculator/dccrfjkmsc"}]},{"problem_id":"unit04-0013","original_source":"cpm-11-90","source_lesson":"11.3.2","category":"Unit 4: Function Families and Transformations","section":"2","unit_section_title":"Unit 4, Section 2: Function Families and Transformations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Matches transformed absolute-value functions to graphs using shifts.","question_html":"<section class=\"problem\" id=\"11-90\"><h2>11-90</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 2: Function Families and Transformations</div><div class=\"audit\">Audit note: Matches absolute-value rules to transformed graphs by reasoning from vertex shifts.</div><p>Match each rule below with its corresponding graph. Can you do this without making any tables?</p><div class=\"three-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li>$y=|x-1|$</li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li>$y=|x|+3$</li></ol></div><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li>$y=|x-1|+3$</li></ol></div></div><div class=\"visual-row\"><img alt=\"Three absolute-value graphs labeled I, II, and III.\" class=\"figure wide\" src=\"assets/11-90.png\"/></div></section>"},{"problem_id":"unit04-0014","original_source":"cpm-11-94","source_lesson":"11.3.3","category":"Unit 4: Function Families and Transformations","section":"2","unit_section_title":"Unit 4, Section 2: Function Families and Transformations","source_type":"Lesson","audit_status":"authoritative","notes":"Investigates a composite absolute-value/quadratic function and describes graph behavior, special points, and structure.","question_html":"<section class=\"problem\" id=\"11-94\">\n<h2>11-94</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 4, Section 2: Function Families and Transformations</div>\n<div class=\"audit\">Audit note: Analyzes a composed absolute-value/quadratic function and describes its graph, special points, and structure.</div>\n<p><strong>FUNKY FUNCTION</strong></p>\n<p>The following relation combines two functions you have studied to make a new kind of graph.</p>\n<p class=\"center\">$f(x)=2|3-2x-x^2|+4$</p>\n<p>With your team, create a <em>complete</em> description of the graph of $f(x)$. Find, or verify, coordinates of special points by evaluating the equation.</p>\n</section>"},<section class="problem" id="11-113">
<h2>11-113</h2>
<div class="tagline"><span class="pill">Review/Preview</span> Sorted to Unit 4, Section 2: Function Families and Transformations</div>
<div class="audit">Audit note: Graphs a rational function and describes domain and range using inequalities; keeps the useful Desmos HW eTool link.</div>
<p>Graph the function $f(x)=\frac{5}{x-2}$. Graph enough points near $x=2$, using decimal values for $x$, until you are sure of the shape. Use inequalities to describe the domain and range of the function. <a class="resource" href="https://www.desmos.com/calculator/anm6topcdf" rel="noopener" target="_blank">11-113 HW eTool</a></p>
</section>,{"problem_id":"unit04-0016","original_source":"cpm-11-131","source_lesson":"11.3.5","category":"Unit 4: Function Families and Transformations","section":"2","unit_section_title":"Unit 4, Section 2: Function Families and Transformations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Investigates a rational function including intercepts and asymptotic behavior.","question_html":"<section class=\"problem\" id=\"11-131\">\n<h2>11-131</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 2: Function Families and Transformations</div>\n<div class=\"audit\">Audit note: Fully investigates a rational function, including intercepts and behavior near a vertical asymptote; kept the useful Desmos HW eTool link.</div>\n<p>Fully investigate the function $g(x)=\\frac{x+2}{x-1}$ on graph paper and name all $x$- and $y$-intercepts. What happens at $x=1$? <a class=\"resource\" href=\"https://www.desmos.com/calculator/ylznui1gwr\" rel=\"noopener\" target=\"_blank\">11-131 HW eTool</a></p>\n</section>","resources":[{"label":"11-131 HW eTool","href":"https://www.desmos.com/calculator/ylznui1gwr"}]},{"problem_id":"unit04-0017","original_source":"cpm-1-46","source_lesson":"1.2.2","category":"Unit 4: Function Families and Transformations","section":"3","unit_section_title":"Unit 4, Section 3: Transformations","source_type":"Lesson","audit_status":"authoritative","notes":"Graphs and describes a transformed absolute-value function.","question_html":"<section class=\"problem\" id=\"1-46\"><h2>1-46</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 1, Section 3: Parent Functions</div><div class=\"audit\">Audit note: Graphs and describes a transformed absolute-value function.</div>\n<p>Fully describe and graph the function $y=|2x-1|$.</p>\n</section>"},{"problem_id":"unit04-0018","original_source":"cpm-CL1-86","source_lesson":"Chapter 1 Closure","category":"Unit 4: Function Families and Transformations","section":"3","unit_section_title":"Unit 4, Section 3: Transformations","source_type":"Closure","audit_status":"authoritative","notes":"Graphs and describes a transformed square-root function, including behavior, domain, and range.","question_html":"<section class=\"problem\" id=\"CL1-86\"><h2>CL 1-86</h2><div class=\"tagline\"><span class=\"pill\">Closure</span> Graphing and describing a function</div><div class=\"audit\">Audit note: Students graph and fully describe a square-root function, including behavior, domain, and range.</div>\n<p>Graph and fully describe the function $y=2\\sqrt{x-1}+3$.</p>\n<div class=\"graph-workspace\"></div>\n</section>"},{"problem_id":"unit04-0019","original_source":"cpm-6-114","source_lesson":"6.2.5","category":"Unit 4: Function Families and Transformations","section":"3","unit_section_title":"Unit 4, Section 3: Transformations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Graphs and describes a transformed cubic function from a table and graph.","question_html":"<section class=\"problem\" id=\"6-114\">\n<h2>6-114</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 3: Transformations</div>\n<div class=\"audit\">Audit note: Graphs and describes a transformed cubic function from a table and graph.</div>\n<div><div><p>Make a table and a graph of<em> $y=(0.5x-3)^3$</em>. Completely describe the graph. <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/o3yukvzsxp\" rel=\"noopener\" target=\"_blank\">6-114 HW eTool</a> </p></div></div>\n</section>","resources":[{"label":"6-114 HW eTool","href":"https://www.desmos.com/calculator/o3yukvzsxp"}]},{"problem_id":"unit04-0020","original_source":"cpm-7-26","source_lesson":"7.1.2","category":"Unit 4: Function Families and Transformations","section":"3","unit_section_title":"Unit 4, Section 3: Transformations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Compares vertical stretch and compression transformations of quadratics.","question_html":"<section class=\"problem\" id=\"7-26\">\n<h2>7-26</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 3: Transformations</div>\n<div class=\"audit\">Audit note: Compares quadratic graphs under vertical stretch and compression transformations.</div>\n<div><p>Sketch the graphs of <em>$y=x^2$</em>, <em>$y=2x^2$,</em> and <em>$y=\\frac{1}{2}x^2$</em> on the same set of axes. Describe the similarities and differences among the graphs. <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/wxjeem5yan\" rel=\"noopener\" target=\"_blank\">7-26 HW eTool</a></p></div>\n</section>","resources":[{"label":"7-26 HW eTool","href":"https://www.desmos.com/calculator/wxjeem5yan"}]},{"problem_id":"unit04-0021","original_source":"cpm-11-2","source_lesson":"11.1.1","category":"Unit 4: Function Families and Transformations","section":"3","unit_section_title":"Unit 4, Section 3: Transformations","source_type":"Lesson","audit_status":"authoritative","notes":"Investigates f(x)+k, f(kx), kf(x), and f(x+k) across multiple function families; general transformation analysis dominates.","question_html":"<section class=\"problem\" id=\"11-2\">\n<h2>11-2</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 1, Section 2: Inputs and Outputs</div>\n<div class=\"audit\">Audit note: Investigates core transformation forms f(x)+k, f(kx), k*f(x), and f(x+k) across linear, quadratic, and exponential functions.</div>\n<p>Investigate the impact of transforming a function by adding or multiplying a constant $k$, where $k$ is any rational number. Consider the following transformations:</p>\n<div class=\"four-col center\"><div>$f(x)+k$</div><div>$f(kx)$</div><div>$k\\cdot f(x)$</div><div>$f(x+k)$</div></div>\n<p><strong>Your Task:</strong> Your teacher will assign your team one or more of the functions below.</p>\n<div class=\"two-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li>$f(x)=-3x+2$</li><li>$f(x)=x^2-6$</li><li>$f(x)=1.5\\cdot 3^x$</li><li>$f(x)=-2x^2+1$</li></ol></div><div><ol class=\"lower-alpha\" start=\"5\" type=\"a\"><li>$f(x)=4x-4$</li><li>$f(x)=5\\cdot\\left(\\frac{1}{2}\\right)^x$</li><li>$f(x)=-1.5x+4$</li><li>$f(x)=\\frac{1}{2}x^2-3$</li></ol></div></div>\n<p>Prepare a poster presentation with your conclusions. Include enough information on your poster so that the impact of $k$ is very clearly communicated without further explanation. Consider both the graph and the algebraic equations.</p>\n<h3 class=\"mini-heading\">Discussion Points</h3><ul><li>What impact does $k$ have on the growth of the function?</li><li>How does $k$ change the starting point or vertex?</li><li>How do changes in the graph connect to changes in the equation?</li><li>Does $k$ slide the graph up or down? Left or right?</li><li>What if $k$ is negative?</li></ul>\n</section>"},{"problem_id":"unit04-0022","original_source":"cpm-11-3","source_lesson":"11.1.1","category":"Unit 4: Function Families and Transformations","section":"3","unit_section_title":"Unit 4, Section 3: Transformations","source_type":"Learning Log","audit_status":"authoritative","notes":"Reflection on how transformations affect slope, growth, and starting point.","question_html":"<section class=\"problem\" id=\"11-3\">\n<h2>11-3</h2>\n<div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Other: Reflection / Study Skills</div>\n<div class=\"audit\">Audit note: Learning Log reflection explaining how f(x)+k and k*f(x) affect slope/growth and starting point.</div>\n<p><strong>Learning Log:</strong> In today's Learning Log entry, consider what happens to the linear function $f(x)=mx+b$ when you make the transformation $f(x)+k$. How does the equation explain what happens to the growth and starting point?</p><p>Now consider what happens when you apply the transformation $k\\cdot f(x)$ to $f(x)=mx+b$. How does the equation explain what happens to the growth and starting point? Give examples in both situations. Title this entry <strong>Transforming Functions</strong> and label it with today's date.</p>\n</section>"},{"problem_id":"unit04-0023","original_source":"cpm-11-4","source_lesson":"11.1.1","category":"Unit 4: Function Families and Transformations","section":"3","unit_section_title":"Unit 4, Section 3: Transformations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Rewrites transformed linear functions and describes graph changes.","question_html":"<section class=\"problem\" id=\"11-4\">\n<h2>11-4</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 1, Section 2: Inputs and Outputs</div>\n<div class=\"audit\">Audit note: Rewrites transformed linear function expressions and describes the transformations; keeps useful eTool link.</div>\n<p>Given the linear function $f(x)=2x-3$, find the new expression for each part below and describe the transformation. <a class=\"resource\" href=\"https://www.desmos.com/calculator/effxvldjnk\" rel=\"noopener\" target=\"_blank\">11-4 HW eTool</a></p><div class=\"four-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li>$f(x)+2$</li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li>$f(2x)$</li></ol></div><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li>$f(x+2)$</li></ol></div><div><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li>$2\\cdot f(x)$</li></ol></div></div>\n</section>","resources":[{"label":"11-4 HW eTool","href":"https://www.desmos.com/calculator/effxvldjnk"}]},{"problem_id":"unit04-0024","original_source":"cpm-11-10","source_lesson":"11.1.1","category":"Unit 4: Function Families and Transformations","section":"3","unit_section_title":"Unit 4, Section 3: Transformations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Rewrites transformed quadratic functions and describes graph effects.","question_html":"<section class=\"problem\" id=\"11-10\">\n<h2>11-10</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 1, Section 2: Inputs and Outputs</div>\n<div class=\"audit\">Audit note: Rewrites transformed quadratic function expressions and describes transformations; keeps useful eTool link.</div>\n<p>Given the function $f(x)=x^2-3$, find the new expression for each part below and describe the transformation. <a class=\"resource\" href=\"https://www.desmos.com/calculator/z4rkboom3r\" rel=\"noopener\" target=\"_blank\">11-10 HW eTool</a></p><div class=\"four-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li>$f(x)+2$</li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li>$2\\cdot f(x)$</li></ol></div><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li>$f(x+2)$</li></ol></div><div><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li>$f(2x)$</li></ol></div></div>\n</section>","resources":[{"label":"11-10 HW eTool","href":"https://www.desmos.com/calculator/z4rkboom3r"}]},{"problem_id":"unit04-0025","original_source":"cpm-11-22","source_lesson":"11.1.2","category":"Unit 4: Function Families and Transformations","section":"3","unit_section_title":"Unit 4, Section 3: Transformations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Rewrites transformed quadratic functions and describes graph changes.","question_html":"<section class=\"problem\" id=\"11-22\">\n<h2>11-22</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 1, Section 2: Inputs and Outputs</div>\n<div class=\"audit\">Audit note: Rewrites transformed quadratic function expressions and describes the associated transformations.</div>\n<p>Given the quadratic function $f(x)=(x-3)^2$, find the new expression for each part below and describe the transformation.</p>\n<div class=\"four-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li>$f(x)-1$</li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li>$-1\\cdot f(x)$</li></ol></div><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li>$f(x-1)$</li></ol></div><div><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li>$f(-1x)$</li></ol></div></div>\n</section>"},{"problem_id":"unit04-0026","original_source":"cpm-11-48","source_lesson":"11.2.2","category":"Unit 4: Function Families and Transformations","section":"3","unit_section_title":"Unit 4, Section 3: Transformations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Applies transformations to a quadratic function and describes graph changes.","question_html":"<section class=\"problem\" id=\"11-48\">\n<h2>11-48</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 2: Function Families and Transformations</div>\n<div class=\"audit\">Audit note: Applies transformations to a quadratic function written in function notation and describes the resulting graph changes.</div>\n<p>Given the quadratic function $f(x)=x^2-3$, find the new expression for each part below and describe the transformation. <a class=\"resource\" href=\"https://www.desmos.com/calculator/5at1pmvjpo\" rel=\"noopener\" target=\"_blank\">11-48 HW eTool</a></p>\n<div class=\"two-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li>$f(x)-2$</li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li>$-2\\cdot f(x)$</li></ol></div></div><div class=\"two-col\"><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li>$f(x-2)$</li></ol></div><div><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li>$f(-2x)$</li></ol></div></div>\n</section>","resources":[{"label":"11-48 HW eTool","href":"https://www.desmos.com/calculator/5at1pmvjpo"}]},{"problem_id":"unit04-0027","original_source":"cpm-CL11-140","source_lesson":"Chapter 11 Closure","category":"Unit 4: Function Families and Transformations","section":"3","unit_section_title":"Unit 4, Section 3: Transformations","source_type":"Closure","audit_status":"authoritative","notes":"Rewrites transformed quadratic functions and describes graph effects.","question_html":"<div class=\"card\" id=\"CL11140\">\n<div class=\"problem-title\">CL 11-140</div>\n<p>Given the function $f(x)=2x^2$, give the equation for each transformation and describe the new graph.</p>\n<div class=\"grid-2\">\n<ol type=\"a\"><li>$f(x)+2$</li></ol>\n<ol start=\"2\" type=\"a\"><li>$2 \\cdot f(x)$</li></ol>\n<ol start=\"3\" type=\"a\"><li>$f(x+2)$</li></ol>\n<ol start=\"4\" type=\"a\"><li>$f(2x)$</li></ol>\n</div>\n</div>"},{"problem_id":"unit04-0028","original_source":"cpm-4-19","source_lesson":"4.1.1","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Multiplies polynomial expressions and rewrites products as sums.","question_html":"<section class=\"problem\" id=\"4-19\"><h2>4-19</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 4: Polynomial Products</div><div class=\"audit\">Audit note: Multiplies polynomial expressions and rewrites products as sums.</div>\n<p>Multiply each polynomial. That is, change each product to a sum.</p>\n<div class=\"choice-grid two-col\">\n<div>a. $(2x+1)(3x-2)$</div>\n<div>b. $(2x+1)(3x^2-2x-5)$</div>\n</div>\n<div class=\"two-column-work\"><div class=\"work-box\"></div><div class=\"work-box\"></div></div>\n</section>"},{"problem_id":"unit04-0029","original_source":"cpm-4-64","source_lesson":"4.2.3","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Reviews multiplying expressions using generic rectangles.","question_html":"<section class=\"problem\" id=\"4-64\"><h2>4-64</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 4: Polynomial Operations</div><div class=\"audit\">Audit note: Reviews multiplying expressions using generic rectangles.</div>\n<p>Use generic rectangles to multiply each of the following expressions.</p>\n<ol class=\"lower-alpha\" type=\"a\"><li>$(x+2)(x-5)$</li><li>$(y+2x)(y+3x)$</li><li>$(3y-8)(-x+y)$</li><li>$(x-3y)(x+3y)$</li></ol>\n<div class=\"workspace workspace-lg\"></div>\n</section>"},{"problem_id":"unit04-0030","original_source":"cpm-4-112","source_lesson":"4.3.1","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Justify equivalence of factored polynomial expressions using commutative structure.","question_html":"<section class=\"problem\" id=\"4-112\"><h2>4-112</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 4: Polynomial Operations</div><div class=\"audit\">Audit note: Justify equivalence of factored polynomial expressions using commutative structure.</div>\n<p>Decide if the statement below is true or false. Justify your response.</p>\n<p>\"The expression $(x+3)(x-1)$ is equivalent to $(x-1)(3+x)$.\"</p>\n<div class=\"workspace-md workspace\"></div>\n</section>"},{"problem_id":"unit04-0031","original_source":"cpm-4-113","source_lesson":"4.3.1","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Multiply polynomial expressions using a generic rectangle or distributive property.","question_html":"<section class=\"problem\" id=\"4-113\"><h2>4-113</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 4: Polynomial Operations</div><div class=\"audit\">Audit note: Multiply polynomial expressions using a generic rectangle or distributive property.</div>\n<p>Find each product by drawing and labeling a generic rectangle or by using the Distributive Property.</p>\n<div class=\"choice-grid two-col\">\n<div><p><strong>a.</strong> $(x+5)(x+4)$</p></div>\n<div><p><strong>b.</strong> $2y(y+3)$</p></div>\n</div>\n<div class=\"workspace-lg workspace\"></div>\n</section>"},{"problem_id":"unit04-0032","original_source":"cpm-CL4-125","source_lesson":"Chapter 4 Closure","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Closure","audit_status":"authoritative","notes":"Polynomial multiplication; rewrite products as sums.","question_html":"<div class=\"card\">\n<div class=\"problem-title\">CL 4-125</div>\n<p>Rewrite each expression below as a product and as a sum.</p>\n<div class=\"grid-3\">\n<ol type=\"a\"><li>$(x+7)(2x-5)$</li></ol>\n<ol start=\"2\" type=\"a\"><li>$5x(y-7)$</li></ol>\n<ol start=\"3\" type=\"a\"><li>$(3x-7)(x^2-2x+11)$</li></ol>\n</div>\n</div>"},{"problem_id":"unit04-0033","original_source":"cpm-5-79","source_lesson":"Lesson 5.2.3","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Multiplies polynomial expressions using difference-of-squares and binomial-square structure.","question_html":"<section class=\"problem\" id=\"5-79\">\n<h2>5-79</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 4: Polynomial Operations</div><div class=\"audit\">Audit note: Multiplies polynomial expressions using difference-of-squares and binomial-square structure.</div>\n<div class=\"contentContainerReference-body\"><div><p>Find the following products. </p><div><div><ol class=\"lower-alpha\" type=\"a\"><li><p>\u00a0$( 4 x + 5 ) ( 4 x - 5 )$\u00a0</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>\u00a0$( 4 x + 5 ) ^ { 2 }$\u00a0</p></li></ol></div></div></div></div>\n</section>"},{"problem_id":"unit04-0034","original_source":"cpm-5-120","source_lesson":"Lesson 5.3.3","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Evaluates a polynomial function, finds a zero, and subtracts polynomial functions.","question_html":"<section class=\"problem\" id=\"5-120\">\n<h2>5-120</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 4: Polynomial Operations</div>\n<div class=\"audit\">Audit note: Evaluates a polynomial function, finds a zero, and subtracts polynomial functions.</div>\n<div><p>For the function <em>$g(x) = x^{3} + x^{2} - 6x$</em>, find the value of each expression below. </p><div class=\"row\"><div class=\"col-sm-3\"><ol class=\"lower-alpha\" type=\"a\"><li><p>\u00a0$g(1)$\u00a0</p></li></ol></div><div class=\"col-sm-3\"><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>\u00a0$g(-1)$\u00a0</p></li></ol></div><div class=\"col-sm-3\"><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p>\u00a0$g(-2)$\u00a0</p></li></ol></div><div class=\"col-sm-3\"><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p>\u00a0$g(10)$\u00a0</p></li></ol></div></div><ol class=\"lower-alpha\" start=\"5\" type=\"a\"><li><p>Find at least one value of <em>$x$</em> for which <em>$g(x) = 0$</em>.</p></li></ol><ol class=\"lower-alpha\" start=\"6\" type=\"a\"><li><p>If $f(x) = x^{2} - x + 3$, find <em>$g(x) - f(x)$</em>.</p></li></ol></div>\n</section>"},{"problem_id":"unit04-0035","original_source":"cpm-7-50","source_lesson":"7.1.4","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Polynomial multiplication and simplification.","question_html":"<section class=\"problem\" id=\"7-50\">\n<h2>7-50</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 4: Polynomial Operations</div>\n<div class=\"audit\">Audit note: Multiplies and simplifies polynomial expressions.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\">Multiply and simplify each expression below. </p><div><div><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">\u00a0$(x\u22123)^2$\u00a0</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p class=\"\">\u00a0$(2m+1)^2$\u00a0</p></li></ol></div></div><div><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p class=\"\">\u00a0$x(x\u22123)(x+1)$\u00a0</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p class=\"\">\u00a0$(2y\u22121)(y^2+7)$\u00a0</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit04-0036","original_source":"cpm-7-58","source_lesson":"7.1.4","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Tests algebraic equations for always/sometimes/never true using polynomial structure and simplification.","question_html":"<section class=\"problem\" id=\"7-58\">\n<h2>7-58</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 4: Polynomial Operations</div>\n<div class=\"audit\">Audit note: Tests algebraic equations for always, sometimes, or never true using polynomial structure and simplification.</div>\n<div class=\"contentContainerReference-body\"><p class=\"\">Determine which of the following equations are true for all values (always true). For those that are not, decide whether they are true for certain values (sometimes true) or not true for any values (never true). Justify your decisions clearly. </p><div><div><ol class=\"lower-alpha\" type=\"a\"><li><p class=\"\">\u00a0$(x-5)^2=x^2+25$\u00a0\u00a0</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p class=\"\">\u00a0$(2x-1)(x+4)=2x^2+7x-4$\u00a0\u00a0</p></li></ol></div></div><div><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p class=\"\">\u00a0$\\frac{2x^2y^3}{y^2}=2x^2y$\u00a0\u00a0</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p class=\"\">\u00a0$(3x-2)(2x+1)=6x^2-x-5$\u00a0\u00a0</p></li></ol></div></div></div>\n</section>"},{"problem_id":"unit04-0037","original_source":"cpm-7-109","source_lesson":"7.2.3","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Generic rectangle, area as sum/product, and polynomial structure.","question_html":"<article class=\"problem\" id=\"7-109\">\n<h3>7-109.</h3>\n<div class=\"meta\"><span class=\"tag\">Review/Preview</span><span>Sorted to Unit 4, Section 4: Polynomial Operations</span></div>\n<div class=\"audit\">Audit note: Uses a generic rectangle to factor and connect area as a sum and a product.</div>\n<p>Find the dimensions of the generic rectangle shown at right and write its area as a sum and a product.</p>\n<div class=\"center\">\n<div aria-label=\"Generic rectangle with entries negative 6x, 4, 9x squared, and negative 6x\" class=\"generic-rect\">\n<div>$-6x$</div><div>$4$</div><div>$9x^2$</div><div>$-6x$</div>\n</div>\n</div>\n</article>"},{"problem_id":"unit04-0038","original_source":"cpm-8-7","source_lesson":"8.1.1","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Review/Preview","audit_status":"authoritative","notes":"Multiplies binomials with generic rectangles; multiplication objective dominates.","question_html":"<article class=\"problem\" id=\"8-7\">\n<h3>8-7.</h3>\n<div class=\"meta\"><span class=\"tag\">Review/Preview</span><span>Sorted to Unit 4, Section 4: Polynomial Operations</span></div>\n<div class=\"audit\">Audit note: Multiplies binomials with a generic rectangle and verifies the diagonal-product pattern.</div>\n<p>Multiply the expressions below using a generic rectangle. Then verify Casey's pattern, that the product of one diagonal equals the product of the other diagonal.</p>\n<ol class=\"lower-alpha\">\n<li>$(4x-1)(3x+5)$</li>\n<li>$(2x-7)^2$</li>\n</ol>\n</article>"},{"problem_id":"unit04-0039","original_source":"cpm-8-27","source_lesson":"8.1.3","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Lesson","audit_status":"authoritative","notes":"Connects polynomial factors and products using a multiplication table; multiplication structure dominates.","question_html":"<article class=\"problem\" id=\"8-27\">\n<h3>8-27.</h3>\n<div class=\"meta\"><span class=\"tag\">Lesson</span><span>Sorted to Unit 4, Section 4: Polynomial Operations</span></div>\n<div class=\"audit\">Audit note: Connects polynomial factors and products using a multiplication table.</div>\n<p>The multiplication table below has factors along the top row and left column. Their product is where the row and column intersect. With your team, complete the table with all of the factors and products.</p>\n<table>\n<tr><th style=\"border-right:3px solid #111;border-bottom:3px solid #111;\">Multiply</th><th style=\"border-left:3px solid #111;border-bottom:3px solid #111;\">$x-2$</th><th style=\"border-bottom:3px solid #111;\">\u00a0</th></tr>\n<tr><th style=\"border-right:3px solid #111;border-top:3px solid #111;\">$x+7$</th><td style=\"border-left:3px solid #111;border-top:3px solid #111;\">\u00a0</td><td style=\"border-top:3px solid #111;\">\u00a0</td></tr>\n<tr><th style=\"border-right:3px solid #111;\">\u00a0</th><td style=\"border-left:3px solid #111;\">$3x^2-5x-2$</td><td>$6x^2+5x+1$</td></tr>\n</table>\n</article>"},{"problem_id":"unit04-0040","original_source":"cpm-11-14","source_lesson":"11.1.1","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Review/Preview","audit_status":"source_only_inferred","notes":"Source-only item not found as a separate row in the uploaded authoritative CSVs; placement inferred from embedded audit text and final rules.","question_html":"<section class=\"problem\" id=\"11-14\">\n<h2>11-14</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 5, Section 2: Factoring Quadratic Expressions</div>\n<div class=\"audit\">Audit note: Multiplies binomial expressions and identifies the equivalent expanded product.</div>\n<p><strong>Multiple Choice:</strong> Which of the following expressions is the product of $(4y-3x)(2y+x)$?</p><div class=\"four-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li>$8y^2-2xy-3x^2$</li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li>$6y^2-2xy-2x^2$</li></ol></div><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li>$8y^2+10xy-3x^2$</li></ol></div><div><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li>$6y^2-2x$</li></ol></div></div>\n</section>"},{"problem_id":"unit04-0041","original_source":"cpm-CP06B-01","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-01\"><h2>CP06B-01</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$2x(x - 1)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0042","original_source":"cpm-CP06B-02","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-02\"><h2>CP06B-02</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$(3x + 2)(2x + 7)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0043","original_source":"cpm-CP06B-03","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-03\"><h2>CP06B-03</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$(2x - 1)(3x + 1)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0044","original_source":"cpm-CP06B-04","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-04\"><h2>CP06B-04</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$2y(x - 1)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0045","original_source":"cpm-CP06B-05","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-05\"><h2>CP06B-05</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$(2y - 1)(3y + 5)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0046","original_source":"cpm-CP06B-06","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-06\"><h2>CP06B-06</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$(x + 3)(x - 3)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0047","original_source":"cpm-CP06B-07","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-07\"><h2>CP06B-07</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$3y(x - y)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0048","original_source":"cpm-CP06B-08","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-08\"><h2>CP06B-08</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$(2x - 5)(x + 4)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0049","original_source":"cpm-CP06B-09","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-09\"><h2>CP06B-09</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$(3x + 7)(3x - 7)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0050","original_source":"cpm-CP06B-10","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-10\"><h2>CP06B-10</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$(4x + 3)^2$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0051","original_source":"cpm-CP06B-11","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-11\"><h2>CP06B-11</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$(x + y)(x + 2)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0052","original_source":"cpm-CP06B-12","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-12\"><h2>CP06B-12</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$(x - 1)(x + y + 1)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0053","original_source":"cpm-CP06B-13","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-13\"><h2>CP06B-13</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$(2y - 3)^2$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0054","original_source":"cpm-CP06B-14","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-14\"><h2>CP06B-14</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$(x + 2)(x + y - 2)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0055","original_source":"cpm-CP06B-15","source_lesson":"Checkpoint 6B","category":"Unit 4: Function Families and Transformations","section":"4","unit_section_title":"Unit 4, Section 4: Polynomial Operations","source_type":"Checkpoint","audit_status":"authoritative","notes":"Multiply polynomial expressions; expanding structure dominates.","question_html":"<section class=\"problem\" id=\"CP06B-15\"><h2>CP06B-15</h2><div class=\"tagline\"><span class=\"pill\">Checkpoint 6B</span> Multiplying Polynomials and Solving Equations with Parentheses</div><div class=\"audit\">Audit note: Students multiply polynomial expressions using the Distributive Property or area reasoning.</div>\n<p><em>Multiply.</em></p>\n<p>$2(x + 3)(3x - 4)$</p>\n<div class=\"workspace\"></div>\n</section>"},{"problem_id":"unit04-0056","original_source":"cpm-1-69","source_lesson":"1.2.4","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Polynomial Structure & Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Graphs and describes a quadratic function over a restricted input set.","question_html":"<section class=\"problem\" id=\"1-69\"><h2>1-69</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 5, Section 4: Graphing Quadratic Functions</div><div class=\"audit\">Audit note: Graphs and describes a quadratic function over a restricted set of inputs.</div>\n<p>Graph and fully describe the function $f(x)=-x^2+3$. Graph values of $x$ from $-3$ to $3$.</p><p>Optional graphing support: <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/hlv1haxvxu\" rel=\"noopener\" target=\"_blank\">1-69 HW eTool</a></p>\n</section>","resources":[{"label":"1-69 HW eTool","href":"https://www.desmos.com/calculator/hlv1haxvxu"}]},{"problem_id":"unit04-0057","original_source":"cpm-2-19","source_lesson":"2.1.2","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Polynomial Structure & Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Graph and identify the shape of a quadratic function.","question_html":"<section class=\"problem\" id=\"2-19\">\n<h2>2-19</h2><div class=\"tagline\"><span class=\"pill\">Lesson</span> Sorted to Unit 2, Section 1: Slope and Rate of Change</div><div class=\"audit\">Audit note: Chapter 2 item sorted to Unit 2, Section 1: Slope and Rate of Change. Category: Linear Relationships. Added 1 resource/eTool link(s).</div>\n<p>\n      What shape will the graph of $y=x^2+2$ be? How can you tell? Justify your prediction by making a table and graphing $y=x^2+2$ on graph paper.\n     Use the <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/plljfvdc1s\" rel=\"noopener\" target=\"_blank\">2-19 HW eTool</a> as needed.</p>\n<div class=\"graph-workspace\"></div>\n</section>","resources":[{"label":"2-19 HW eTool","href":"https://www.desmos.com/calculator/plljfvdc1s"}]},{"problem_id":"unit04-0058","original_source":"cpm-CL2-108","source_lesson":"Chapter 2 Closure","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Polynomial Structure & Quadratic Graphs","source_type":"Closure","audit_status":"authoritative","notes":"Complete table, graph quadratic, describe features, and state domain/range.","question_html":"<section class=\"problem\" id=\"CL2-108\"><h2>CL 2-108</h2><div class=\"tagline\"><span class=\"pill\">Closure</span> Quadratic table and graph description</div><div class=\"audit\">Audit note: Students complete a table for a quadratic rule, graph it, and describe key features.</div>\n<p>Copy and complete the table below for the rule $y=x^2-6x+5$. Then graph the rule on graph paper.</p>\n<table><tbody><tr><th>$x$</th><td>$-1$</td><td>$0$</td><td>$1$</td><td>$2$</td><td>$3$</td><td>$4$</td><td>$5$</td><td>$6$</td><td>$7$</td></tr><tr><th>$y$</th><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td><td></td></tr></tbody></table>\n<ol class=\"lower-alpha\" type=\"a\"><li>Completely describe the graph.</li><li>Is the relation a function?</li><li>State the domain and range.</li></ol>\n</section>"},{"problem_id":"unit04-0059","original_source":"cpm-3-53","source_lesson":"3.2.2","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Polynomial Structure & Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Quadratic table/graph features belong with polynomial structure and quadratic graphs.","question_html":"<section class=\"problem\" id=\"3-53\">\n<h2>3-53</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 3, Section 2: Area Models and Algebraic Expressions</div><div class=\"audit\">Audit note: Reviews table, graph, and intercepts for a quadratic rule.</div>\n<p>On graph paper, make an $x \\to y$ table and graph $y=2x^2-x-3$. Find its $x$- and $y$-intercepts.</p>\n</section>"},{"problem_id":"unit04-0060","original_source":"cpm-4-27","source_lesson":"4.1.2","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Connecting Polynomial Structure and Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Reviews graphing a quadratic from a rule with a table, graph, and intercepts.","question_html":"<section class=\"problem\" id=\"4-27\"><h2>4-27</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 5: Polynomial Structure and Quadratic Graphs</div><div class=\"audit\">Audit note: Reviews graphing a quadratic from a rule with a table, graph, and intercepts.</div>\n<p>Create a table and graph the rule $y=10-x^2+3x$. Label its $x$- and $y$-intercepts. <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/shpgywk7ie\" rel=\"noopener\" target=\"_blank\">4-27 HW eTool</a></p>\n<div class=\"graph-workspace\"></div><div class=\"workspace workspace-sm\"></div>\n</section>","resources":[{"label":"4-27 HW eTool","href":"https://www.desmos.com/calculator/shpgywk7ie"}]},{"problem_id":"unit04-0061","original_source":"cpm-4-101","source_lesson":"4.3.1","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Connecting Polynomial Structure and Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Make a table and graph a quadratic; identify x-intercepts.","question_html":"<section class=\"problem\" id=\"4-101\"><h2>4-101</h2><div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 5: Polynomial Structure &amp; Quadratic Graphs</div><div class=\"audit\">Audit note: Make a table and graph a quadratic; identify x-intercepts.</div>\n<p>Make a table and graph the rule $y=-x^2+x+2$ on graph paper. Label the $x$-intercepts. <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/65d7k0kma3\" rel=\"noopener\" target=\"_blank\">4-101 HW eTool</a></p>\n<div class=\"graph-workspace\"></div>\n<div class=\"workspace-lg workspace\"></div>\n</section>","resources":[{"label":"4-101 HW eTool","href":"https://www.desmos.com/calculator/65d7k0kma3"}]},{"problem_id":"unit04-0062","original_source":"cpm-6-121","source_lesson":"6.2.5","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Polynomial Structure & Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Graphs a quadratic rule and identifies intercepts and vertex.","question_html":"<section class=\"problem\" id=\"6-121\">\n<h2>6-121</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 4, Section 5: Polynomial Structure &amp; Quadratic Graphs</div>\n<div class=\"audit\">Audit note: Graphs a quadratic rule and identifies intercepts and vertex.</div>\n<div><div><p>Graph the rule <em>$y=-x^2+4x$</em> and label its intercepts and vertex.<span> </span><a class=\"etool-link\" href=\"https://www.desmos.com/calculator/2ydigtvd2v\" rel=\"noopener\" target=\"_blank\">6-121 HW eTool</a>. </p></div></div>\n</section>","resources":[{"label":"6-121 HW eTool","href":"https://www.desmos.com/calculator/2ydigtvd2v"}]},{"problem_id":"unit04-0063","original_source":"cpm-8-11","source_lesson":"8.1.1","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Polynomial Structure & Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Graphs a quadratic and identifies intercepts and vertex from the rule.","question_html":"<article class=\"problem\" id=\"8-11\">\n<h3>8-11.</h3>\n<div class=\"meta\"><span class=\"tag\">Review/Preview</span><span>Sorted to Unit 5, Section 4: Graphing Quadratic Functions</span></div>\n<div class=\"audit\">Audit note: Graphs a quadratic and identifies intercepts and vertex from the rule.</div>\n<p>On graph paper, graph $y=x^2-2x-8$. <a class=\"etool\" href=\"https://www.desmos.com/calculator/chxrrfcuvt\" rel=\"noopener\" target=\"_blank\">8-11 HW eTool</a></p>\n<ol class=\"lower-alpha\">\n<li>Name the $y$-intercept. What is the connection between the $y$-intercept and the rule $y=x^2-2x-8$?</li>\n<li>Name the $x$-intercepts.</li>\n<li>Find the lowest point of the graph, called the vertex.</li>\n</ol>\n</article>","resources":[{"label":"8-11 HW eTool","href":"https://www.desmos.com/calculator/chxrrfcuvt"}]},{"problem_id":"unit04-0064","original_source":"cpm-8-18","source_lesson":"8.1.2","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Polynomial Structure & Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Identifies x- and y-intercepts from graphs, a table, and an equation.","question_html":"<article class=\"problem\" id=\"8-18\">\n<h3>8-18.</h3>\n<div class=\"meta\"><span class=\"tag\">Review/Preview</span><span>Sorted to Unit 5, Section 4: Graphing Quadratic Functions</span></div>\n<div class=\"audit\">Audit note: Identifies $x$- and $y$-intercepts from graphs, a table, and an equation.</div>\n<p>For each rule represented below, state the $x$- and $y$-intercepts, if possible.</p>\n<img alt=\"Representations for problem 8-18: graphs, a table, and an equation.\" class=\"wide-img\" src=\"assets/8-18.png\"/>\n</article>"},{"problem_id":"unit04-0065","original_source":"cpm-8-44","source_lesson":"8.1.4","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Polynomial Structure & Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Matches quadratic rules to graphs using opening direction and vertex/shift information.","question_html":"<article class=\"problem\" id=\"8-44\">\n<h3>8-44.</h3>\n<div class=\"meta\"><span class=\"tag\">Review/Preview</span><span>Sorted to Unit 5, Section 4: Graphing Quadratic Functions</span></div>\n<div class=\"audit\">Audit note: Matches quadratic rules to graphs by using opening direction and vertical shift/vertex location.</div>\n<p>Match each rule below with its corresponding graph. Can you do this without making any tables? Explain your selections.</p>\n<img alt=\"Three quadratic rules and three possible parabola graphs for matching.\" class=\"figure wide-figure\" src=\"assets/8-44.png\"/>\n</article>"},{"problem_id":"unit04-0066","original_source":"cpm-8-58","source_lesson":"8.2.1","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Polynomial Structure & Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Graphs a quadratic and labels vertex and intercepts; pure graph-feature review.","question_html":"<section class=\"problem\" id=\"8-58\">\n<h2>8-58</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 5, Section 4: Graphing Quadratic Functions</div>\n<div class=\"audit\">Audit note: Graphs a quadratic function and identifies its vertex and intercepts.</div>\n<div><p>Graph <em>$y=x^2-8x+7$</em> and label its vertex, <em>$x\\text{-intercepts}$</em>, and <em>$y\\text{-intercepts}$</em>.  <a class=\"etool-link\" href=\"https://www.desmos.com/calculator/qzncksavo9\" rel=\"noopener\" target=\"_blank\">8-58 HW eTool</a></p></div>\n</section>","resources":[{"label":"8-58 HW eTool","href":"https://www.desmos.com/calculator/qzncksavo9"}]},{"problem_id":"unit04-0067","original_source":"cpm-8-60","source_lesson":"8.2.1","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Polynomial Structure & Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Uses tables to identify and interpret x- and y-intercepts of graphs.","question_html":"<section class=\"problem\" id=\"8-60\">\n<h2>8-60</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 5, Section 4: Graphing Quadratic Functions</div>\n<div class=\"audit\">Audit note: Uses tables to identify and interpret x- and y-intercepts of corresponding graphs.</div>\n<div><p>Based on the tables below, say as much as you can about the <em>$x$</em>- and $y$-intercepts of the corresponding graphs.</p><p><img alt=\"Captured tables a, b, and c for problem 8-60.\" class=\"figure-img wide-figure\" src=\"assets/8-60.png\"/></p></div>\n</section>"},{"problem_id":"unit04-0068","original_source":"cpm-9-7","source_lesson":"9.1.1","category":"Unit 4: Function Families and Transformations","section":"5","unit_section_title":"Unit 4, Section 5: Polynomial Structure & Quadratic Graphs","source_type":"Review/Preview","audit_status":"authoritative","notes":"Classifies equations as producing linear or quadratic graphs based on structure.","question_html":"<section class=\"problem\" id=\"9-7\">\n<h2>9-7</h2>\n<div class=\"tagline\"><span class=\"pill\">Review/Preview</span> Sorted to Unit 5, Section 4: Graphing Quadratic Functions</div>\n<div class=\"audit\">Audit note: Classifies equations as producing linear or quadratic graphs based on structure.</div>\n<div><p>For each of the following equations, indicate whether its graph would be a line or a parabola.</p>\n<div class=\"two-col\"><div><ol class=\"lower-alpha\" type=\"a\"><li><p>$5x+2y=7$</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"2\" type=\"a\"><li><p>$y=3x^2$</p></li></ol></div></div>\n<div class=\"two-col\"><div><ol class=\"lower-alpha\" start=\"3\" type=\"a\"><li><p>$y=3$</p></li></ol></div><div><ol class=\"lower-alpha\" start=\"4\" type=\"a\"><li><p>$4x^2+3x=7+y$</p></li></ol></div></div></div>\n</section>"}];
